create table dirkspzm32.pps_ruestmatrix (
    sid                  varchar2(2 char) not null enable,
    firma_nr             number(2, 0) not null enable,
    rm_name              varchar2(50 char) not null enable,
    created_date         date not null enable,
    created_login_id     number(*, 0),
    last_change_date     date,
    last_change_login_id number(*, 0),
    bezeichnung          varchar2(50 char),
    text                 varchar2(50 char)
);

alter table dirkspzm32.pps_ruestmatrix
    add constraint pk_pps_ruestmatrix
        primary key ( rm_name,
                      firma_nr,
                      sid )
            using index enable;


